		assertThat(second).isEqualTo(first);
		assertThat(first.key()).startsWith("lmdb-plan-shape:test:");
		assertThat(first.operatorCodes()).containsExactly("extension", "group", "filter", "exists", "sp", "join",
				"sp", "sp");
		assertThat(first.statementPatternCount()).isEqualTo(3);
		assertThat(first.filterCount()).isEqualTo(1);
		assertThat(first.existsCount()).isEqualTo(1);
		assertThat(first.groupCount()).isEqualTo(1);
